INSERT INTO `object_validations` (`id`, `object_id`, `label`, `description`, `type`, `trigger_code`, `error_message`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `edit_type`, `is_active`, `source`, `name`, `version`) VALUES ('fdee4384-394a-431c-bda4-161568bed6a1', '3f49c30f-5d59-11e6-a130-5cc5d4d378cb', '自动生成活动名称', '自动生成活动名称', 'trigger', 'from orionbase.common import models\nfrom django.utils.timezone import utc, localtime, get_current_timezone, make_aware, now\nimport pytz\nif instance and instance.id:\n    event_place = instance.event_place or u\'未填写\'\n    event_record_type = instance.record_type.name\n    event_record_type_label = instance.record_type.label.replace(u\'(报告)\',\'\')\n    if event_record_type in (u\'cs_department\',u\'cs_department__report\'):\n        if type(instance.date_1) == datetime.date:\n            event_date=(instance.date_1).strftime(\'%Y%m%d\')\n            date = make_aware(datetime.datetime.strptime(str(instance.date_1),\'%Y-%m-%d\')).astimezone(pytz.timezone(\'Asia/Shanghai\')).strftime(\"%Y-%m-%d %H:%M:%S\")\n        else:\n            event_date = make_aware(datetime.datetime.strptime(instance.date_1, \'%Y-%m-%d\')).strftime(\'%Y%m%d\')\n            date = make_aware(datetime.datetime.strptime(instance.date_1, \'%Y-%m-%d\')).astimezone(pytz.timezone(\'Asia/Shanghai\')).strftime(\"%Y-%m-%d %H:%M:%S\")\n        event_theme = instance.picklist_3.label or \'\'\n        attende = int(instance.number_1 or 0) + (instance.number_2 or 0)\n        models.Events.advance_objects.filter(id=instance.id).update(name=u\'{}-{}-{}\'.format(event_place, event_record_type_label, event_date),\n                                                                    event_start_time=date,event_end_time=date,\n                                                                    text_1=event_theme,number_3=attende)\n    elif event_record_type in (u\'cs_patient_education_meeting\',u\'cs_patient_education_meeting__report\'):\n        if type(instance.event_start_time) == datetime.datetime:\n            event_date = localtime(instance.event_start_time.replace(tzinfo=utc)).strftime(\'%Y%m%d\')\n            date = localtime(instance.event_start_time.replace(tzinfo=utc)).strftime(\'%Y-%m-%d\')\n        else:\n            event_date = make_aware(datetime.datetime.strptime(instance.event_start_time, \'%Y-%m-%d %H:%M:%S\')).strftime(\'%Y%m%d\')\n            date = make_aware(datetime.datetime.strptime(instance.event_start_time, \'%Y-%m-%d %H:%M:%S\')).strftime(\'%Y-%m-%d\')\n        event_theme = instance.picklist_3.label or \'\'\n        attende = int(instance.number_1 or 0) + (instance.number_2 or 0)\n        models.Events.advance_objects.filter(id=instance.id).update(name=u\'{}-{}-{}\'.format(event_place, event_record_type_label, event_date),\n                                                                    date_1=date,text_1=event_theme,number_3=attende)\n    else:\n        if type(instance.event_start_time) == datetime.datetime:\n            event_date = localtime(instance.event_start_time.replace(tzinfo=utc)).strftime(\'%Y%m%d\')\n            date = localtime(instance.event_start_time.replace(tzinfo=utc)).strftime(\'%Y-%m-%d\')\n        else:\n            event_date = make_aware(datetime.datetime.strptime(instance.event_start_time, \'%Y-%m-%d %H:%M:%S\')).strftime(\'%Y%m%d\')\n            date = make_aware(datetime.datetime.strptime(instance.event_start_time, \'%Y-%m-%d %H:%M:%S\')).strftime(\'%Y-%m-%d\')\n        attende = int(instance.number_1 or 0) + (instance.number_2 or 0)\n        models.Events.advance_objects.filter(id=instance.id).update(name=u\'{}-{}-{}\'.format(event_place, event_record_type_label, event_date),\n                                                                    date_1=date,number_3=attende)\n', '', '0', '1', '2020-08-10 06:45:37', '1', '2020-08-18 08:53:54', 'post_save', '1', 'custom', 'cs_event_name', '1');
INSERT INTO `object_validations` (`id`, `object_id`, `label`, `description`, `type`, `trigger_code`, `error_message`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `edit_type`, `is_active`, `source`, `name`, `version`) VALUES ('6bc74574-a65e-43ea-8ab9-b101ba66119d', '3f49c30f-5d59-11e6-a130-5cc5d4d378cb', '自动测算会议费用', '自动测算会议费用', 'trigger', 'from orionbase.common import models\nfrom decimal import Decimal\ntotal_expense = sum(\ninstance.eventexpenses_set.filter(deleted=0, total_expense__isnull=False).values_list(\'total_expense\', flat=True))\nif instance.id:\n    other_expense = sum(models.CustomObjects5.objects.filter(deleted=0, event_1_id=instance.id).values_list(\'number_1\',flat=True))\n    total_expense += other_expense\nexpenses = Decimal(total_expense).quantize(Decimal(\'0.00\'))\nif instance.record_type.name.endswith(\'__report\'):\n    event_budget = Decimal(instance.event_budget).quantize(Decimal(\'0.00\'))\n    if str(expenses) and str(event_budget):\n        expenses_diff = max(expenses - event_budget, 0)\n    else:\n        expenses_diff = 0\n    models.Events.advance_objects.filter(id=instance.id).update(event_expense=expenses,\n                                                                number_4=expenses_diff\n                                                                )\nelse:\n    models.Events.advance_objects.filter(id=instance.id).update(event_budget=expenses)', '', '0', '1', '2020-08-10 06:45:37', '1', '2020-08-25 13:00:42', 'post_save_page', '1', 'custom', 'cs_event_expense_event', '1');
INSERT INTO `object_validations` (`id`, `object_id`, `label`, `description`, `type`, `trigger_code`, `error_message`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `edit_type`, `is_active`, `source`, `name`, `version`) VALUES ('b7544a84-6b03-488d-9874-f9bcfdd11c51', '3f49c30f-5d59-11e6-a130-5cc5d4d378cb', '会议时间验证', '会议时间验证', 'trigger', 'from django.utils.timezone import utc, localtime, get_current_timezone, make_aware, now\nuserid = instance.owner.id\n# 时间验证\nif instance:\n    if instance.record_type.name in (u\'cs_department\', u\'cs_department__report\'):\n        if type(instance.date_1) == datetime.date:\n            start_time = make_aware(datetime.datetime.strptime(str(instance.date_1), \'%Y-%m-%d\'))\n            end_time = make_aware(datetime.datetime.strptime(str(instance.date_1), \'%Y-%m-%d\'))\n        else:\n            start_time = make_aware(datetime.datetime.strptime(instance.date_1, \'%Y-%m-%d\'))\n            end_time=make_aware(datetime.datetime.strptime(instance.date_1, \'%Y-%m-%d\'))\n    else:\n        if type(instance.event_start_time) == datetime.datetime:\n            start_time = localtime(instance.event_start_time.replace(tzinfo=utc))\n        else:\n            start_time = make_aware(datetime.datetime.strptime(instance.event_start_time, \'%Y-%m-%d %H:%M:%S\'))\n        if type(instance.event_end_time) == datetime.datetime:\n            end_time = localtime(instance.event_end_time.replace(tzinfo=utc))\n        else:\n            end_time = make_aware(datetime.datetime.strptime(instance.event_end_time, \'%Y-%m-%d %H:%M:%S\'))\n    if (instance.state.name == \'save\') and instance.record_type.name.find(\'_report\') == -1:\n        if start_time <= now():\n            message = \'会议计划开始时间不能早于当前时间\'\n            raise create_validation_trigger_rule_errors(message)\n    if start_time > end_time and instance.record_type.name not in (u\'cs_department\', u\'cs_department__report\'):\n        message = \'会议开始时间不能晚于结束时间\'\n        raise create_validation_trigger_rule_errors(message)', '', '0', '1', '2020-08-10 06:45:37', '1', '2020-08-18 08:53:54', 'pre_save', '1', 'custom', 'cs_event_time_trigger', '1');
INSERT INTO `object_validations` (`id`, `object_id`, `label`, `description`, `type`, `trigger_code`, `error_message`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `edit_type`, `is_active`, `source`, `name`, `version`) VALUES ('f083128a-5353-4ab0-b4ac-462307111ee0', '3f49c30f-5d59-11e6-a130-5cc5d4d378cb', '会议报告阶段自动拷贝计划阶段成本中心', '会议报告阶段自动拷贝计划阶段成本中心', 'trigger', 'from orionbase.common import models\nuserid = instance.owner.id\n# 报告阶段自动拷贝计划阶段成本中心\nif (instance.state.name == \'save\') and instance.record_type.name.find(\'_report\'):\n    if instance.id and instance.event_id:\n        to_copy_data = []\n        from_data = models.CustomObjects4.objects.filter(deleted=0,event_1_id=instance.event_id)\n        if from_data:\n            for data in from_data:\n                data.id = None\n                data.event_1_id = instance.id\n                to_copy_data.append(data)\n        if to_copy_data:\n            models.CustomObjects4.objects.bulk_create(to_copy_data, batch_size=500)', '', '0', '1', '2020-08-10 06:45:37', '1', '2020-08-24 07:17:39', 'post_save_page', '1', 'custom', 'cs_copy_cost_center', '1');
INSERT INTO `object_validations` (`id`, `object_id`, `label`, `description`, `type`, `trigger_code`, `error_message`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `edit_type`, `is_active`, `source`, `name`, `version`) VALUES ('8643160f-a6db-4523-9531-e1dee464cd54', '3f49c30f-5d59-11e6-a130-5cc5d4d378cb', '会议报告提交审批验证', '会议报告提交审批验证', 'trigger', 'from orionbase.common import models\nfrom decimal import Decimal\nif instance.record_type.name.endswith(\'__report\') and instance.state.name == u\'sent_approval\':\n    if instance.number_4 > 0 and not instance.longtext_1:\n        raise create_validation_trigger_rule_errors(u\'请填写超预算原因!\')\n    if instance.record_type.name not in (u\'cs_department__report\') and not models.EventSchedules.objects.filter(deleted=0,event=instance.id).count():\n        raise create_validation_trigger_rule_errors(u\'请填写会议日程!\')\n    # 计算成本中心及成本中心加和\n    if not models.CustomObjects4.objects.filter(deleted=0,event_1_id=instance.id).count():\n        raise create_validation_trigger_rule_errors(u\'请填写成本中心!\')\n    cost_center = sum(models.CustomObjects4.objects.filter(deleted=0,event_1_id=instance.id).values_list(\'number_1\',flat=True))\n    if  Decimal(cost_center).quantize(Decimal(\'0.00\')) != Decimal(100).quantize(Decimal(\'0.00\')):\n        message = u\'成本中心加和应为1.00,实际加和为{}\'.format(Decimal(cost_center/100).quantize(Decimal(\'0.00\')))\n        raise create_validation_trigger_rule_errors(message)\n    # 附件验证\n    qiandaobiao_attachment = models.Attachments.objects.filter(object__name=\'event\',record=instance.id,attachment_group__name=(\'qiandaobiao\')).count()\n    huiyixianchang_attachment = models.Attachments.objects.filter(object__name=\'event\', record=instance.id,attachment_group__name=(\'huiyixianchang\')).count()\n    if qiandaobiao_attachment < 1:\n        raise create_validation_trigger_rule_errors(u\'请上传签到表附件\')\n    if huiyixianchang_attachment < 1:\n        raise create_validation_trigger_rule_errors(u\'请上传会议现场附件\')\n', '', '0', '1', '2020-08-10 06:45:37', '1', '2020-08-24 07:56:57', 'pre_save', '1', 'custom', 'cs_event_report_trigger', '1');
